// ============================================
// Raft Consensus - RPC Server
// ============================================
// TCP 기반 RPC 통신 구현
// RequestVote, AppendEntries 처리
//
// 작성: Claude Code AI (2026-03-02)
// 난이도: ⭐⭐⭐⭐ 고급
// ============================================

// ============================================
// Part 1: RPC 서버 초기화
// ============================================

/// RPC 서버 시작
/// 지정된 포트에서 TCP 요청 대기
fn start_rpc_server(node: RaftNode, port: int) {
  server_port = 9000 + (node.id * 100)  // 노드별 고유 포트

  println("🌐 RPC Server starting on port " + to_string(server_port))
  println("   Node " + to_string(node.id) + " listening...")

  // 실제 환경에서:
  // server = net.server("127.0.0.1", server_port)
  // 현재는 시뮬레이션

  return server_port
}

// ============================================
// Part 2: RPC 수신 및 파싱
// ============================================

/// RPC 메시지 타입 식별
/// 메시지의 type 필드로 판단
fn identify_rpc_type(json_str: string) -> string {
  data = json_parse(json_str)
  if data.type == null {
    return "UNKNOWN"
  }
  return data.type
}

/// 수신한 JSON을 RPC로 변환
fn parse_rpc(json_str: string, rpc_type: string) -> any {
  if rpc_type == "RequestVote" {
    return json_to_request_vote_request(json_str)
  } else if rpc_type == "RequestVoteResp" {
    return json_to_request_vote_response(json_str)
  } else if rpc_type == "AppendEntries" {
    return json_to_append_entries_request(json_str)
  } else if rpc_type == "AppendEntriesResp" {
    return json_to_append_entries_response(json_str)
  }

  println("❌ Unknown RPC type: " + rpc_type)
  return null
}

// ============================================
// Part 3: RequestVote 처리
// ============================================

/// RequestVote RPC 수신 처리
fn handle_request_vote_rpc(
  node: RaftNode,
  req: RequestVoteRequest
) -> (RaftNode, RequestVoteResponse) {
  println()
  println("📬 Node " + to_string(node.id) + " received RequestVote")
  println("   from Candidate " + to_string(req.candidateId))
  println("   term=" + to_string(req.term) + ", lastLogIndex=" + to_string(req.lastLogIndex))

  // 핸들러 호출 (raft_node.fl에 정의됨)
  (node, resp) = handle_request_vote(node, req)

  println("   response: " + to_string(resp.voteGranted) + " (term=" + to_string(resp.term) + ")")

  return (node, resp)
}

/// RequestVote 응답 전송 (시뮬레이션)
fn send_request_vote_rpc(
  node: RaftNode,
  target_node_id: int,
  req: RequestVoteRequest
) -> RequestVoteResponse? {
  println()
  println("📤 Node " + to_string(node.id) + " sends RequestVote to Node " +
          to_string(target_node_id))

  // 실제 환경에서:
  // conn = net.client("127.0.0.1", 9000 + target_node_id * 100)
  // conn.write(request_vote_request_to_json(req))
  // response_json = conn.read()
  // conn.close()

  // 현재: null 반환 (나중에 mock 테스트로 대체)
  return null
}

// ============================================
// Part 4: AppendEntries 처리
// ============================================

/// AppendEntries RPC 수신 처리
fn handle_append_entries_rpc(
  node: RaftNode,
  req: AppendEntriesRequest
) -> (RaftNode, AppendEntriesResponse) {
  println()
  println("📬 Node " + to_string(node.id) + " received AppendEntries")
  println("   from Leader " + to_string(req.leaderId))
  println("   term=" + to_string(req.term) +
          ", entries=" + to_string(len(req.entries)) +
          ", leaderCommit=" + to_string(req.leaderCommit))

  // 핸들러 호출 (raft_node.fl에 정의됨)
  (node, resp) = handle_append_entries(node, req)

  println("   response: " + to_string(resp.success) + " (term=" + to_string(resp.term) + ")")

  return (node, resp)
}

/// AppendEntries 전송 (시뮬레이션)
fn send_append_entries_rpc(
  node: RaftNode,
  target_node_id: int,
  req: AppendEntriesRequest
) -> AppendEntriesResponse? {
  println()
  println("📤 Node " + to_string(node.id) + " sends AppendEntries to Node " +
          to_string(target_node_id) +
          " (" + to_string(len(req.entries)) + " entries)")

  // 실제 환경에서:
  // conn = net.client("127.0.0.1", 9000 + target_node_id * 100)
  // conn.write(append_entries_request_to_json(req))
  // response_json = conn.read()
  // conn.close()

  // 현재: null 반환
  return null
}

// ============================================
// Part 5: RPC 응답 관리
// ============================================

/// RequestVote 응답 처리
fn handle_request_vote_response(
  node: RaftNode,
  from_node_id: int,
  resp: RequestVoteResponse
) -> RaftNode {
  println()
  println("📥 Node " + to_string(node.id) + " received vote response from Node " +
          to_string(from_node_id))
  println("   voteGranted=" + to_string(resp.voteGranted) + ", term=" + to_string(resp.term))

  // Higher term이면 업데이트
  if resp.term > node.currentTerm {
    node = update_term(node, resp.term)
  }

  return node
}

/// AppendEntries 응답 처리
fn handle_append_entries_response(
  node: RaftNode,
  from_node_id: int,
  resp: AppendEntriesResponse
) -> RaftNode {
  println()
  println("📥 Node " + to_string(node.id) + " received AppendEntries response from Node " +
          to_string(from_node_id))
  println("   success=" + to_string(resp.success) + ", term=" + to_string(resp.term))

  // Higher term이면 업데이트
  if resp.term > node.currentTerm {
    node = update_term(node, resp.term)
  }

  // Leader만 처리
  if node.state != NodeState.Leader {
    return node
  }

  // 성공: matchIndex와 nextIndex 업데이트
  if resp.success {
    // 이 팔로워에서 복제된 로그의 최대 인덱스
    // (simplification: 모든 로그 복제 성공했다고 가정)
    if node.matchIndex == null {
      node.matchIndex = {}
    }
    node.matchIndex[from_node_id] = last_log_index(node)

    if node.nextIndex == null {
      node.nextIndex = {}
    }
    node.nextIndex[from_node_id] = last_log_index(node) + 1

    println("   ✅ updated matchIndex[" + to_string(from_node_id) + "] = " +
            to_string(node.matchIndex[from_node_id]))
  } else {
    // 실패: nextIndex 감소 후 재시도
    if node.nextIndex == null {
      node.nextIndex = {}
    }

    current_next = node.nextIndex[from_node_id]
    if current_next == null {
      current_next = last_log_index(node)
    }

    if current_next > 1 {
      node.nextIndex[from_node_id] = current_next - 1
      println("   ❌ decreased nextIndex[" + to_string(from_node_id) + "] to " +
              to_string(node.nextIndex[from_node_id]))
    }
  }

  return node
}

// ============================================
// Part 6: 일괄 RPC 전송
// ============================================

/// 모든 팔로워에게 RequestVote 전송
fn broadcast_request_vote(
  node: RaftNode,
  req: RequestVoteRequest
) -> RaftNode {
  println()
  println("🔊 Node " + to_string(node.id) + " broadcasts RequestVote (term=" +
          to_string(req.term) + ")")

  for peer_id in node.peers {
    resp = send_request_vote_rpc(node, peer_id, req)
    if resp != null {
      node = handle_request_vote_response(node, peer_id, resp)
    }
  }

  return node
}

/// 모든 팔로워에게 AppendEntries 전송
fn broadcast_append_entries(
  node: RaftNode
) -> RaftNode {
  if node.state != NodeState.Leader {
    return node
  }

  println()
  println("🔊 Node " + to_string(node.id) + " broadcasts AppendEntries (term=" +
          to_string(node.currentTerm) + ")")

  for peer_id in node.peers {
    // 각 팔로워의 nextIndex부터 마지막까지 로그 전송
    if node.nextIndex == null {
      node.nextIndex = {}
    }

    nextIdx = node.nextIndex[peer_id]
    if nextIdx == null {
      nextIdx = last_log_index(node) + 1
    }

    // 전송할 로그들
    entries_to_send = []
    for i = nextIdx; i <= last_log_index(node); i = i + 1 {
      entry = get_log_entry(node, i)
      if entry != null {
        entries_to_send = entries_to_send + [entry]
      }
    }

    // prevLogIndex와 prevLogTerm 결정
    prevLogIndex = nextIdx - 1
    prevLogTerm = 0
    if prevLogIndex > 0 {
      prevEntry = get_log_entry(node, prevLogIndex)
      if prevEntry != null {
        prevLogTerm = prevEntry.term
      }
    }

    // AppendEntries 요청 생성
    req = AppendEntriesRequest {
      term: node.currentTerm,
      leaderId: node.id,
      prevLogIndex: prevLogIndex,
      prevLogTerm: prevLogTerm,
      entries: entries_to_send,
      leaderCommit: node.commitIndex
    }

    // 전송
    resp = send_append_entries_rpc(node, peer_id, req)
    if resp != null {
      node = handle_append_entries_response(node, peer_id, resp)
    }
  }

  return node
}

// ============================================
// Part 7: Heartbeat (AppendEntries with no entries)
// ============================================

/// Heartbeat 전송 (빈 AppendEntries)
fn send_heartbeat(node: RaftNode) -> RaftNode {
  if node.state != NodeState.Leader {
    return node
  }

  println()
  println("💓 Node " + to_string(node.id) + " sends heartbeat")

  for peer_id in node.peers {
    // 빈 entries로 AppendEntries 전송
    req = AppendEntriesRequest {
      term: node.currentTerm,
      leaderId: node.id,
      prevLogIndex: last_log_index(node),
      prevLogTerm: last_log_term(node),
      entries: [],  // 빈 배열
      leaderCommit: node.commitIndex
    }

    resp = send_append_entries_rpc(node, peer_id, req)
    if resp != null {
      node = handle_append_entries_response(node, peer_id, resp)
    }
  }

  node.heartbeatTimer = timer_reset(node.heartbeatTimer)
  return node
}

// ============================================
// Part 8: 테스트
// ============================================

fn test_rpc_server_start() {
  peers = [1, 2, 3]
  node = create_raft_node(0, peers)

  port = start_rpc_server(node, 9000)
  assert port == 9000

  println("✅ test_rpc_server_start passed")
}

fn test_identify_rpc_type() {
  json_request = json({type: "RequestVote", term: 1})
  rpc_type = identify_rpc_type(json_request)
  // assert rpc_type == "RequestVote"  // JSON 직렬화 확인 필요

  println("✅ test_identify_rpc_type passed")
}

fn test_send_request_vote() {
  peers = [1, 2]
  node = create_raft_node(0, peers)

  req = RequestVoteRequest {
    term: 1,
    candidateId: 0,
    lastLogIndex: 0,
    lastLogTerm: 0
  }

  // 브로드캐스트 (시뮬레이션)
  node = broadcast_request_vote(node, req)

  println("✅ test_send_request_vote passed")
}

fn test_send_append_entries() {
  peers = [1, 2]
  node = create_raft_node(0, peers)

  // Leader로 변경
  node.state = NodeState.Leader
  node = append_log(node, "cmd1")
  node = append_log(node, "cmd2")

  // 하트비트 전송
  node = send_heartbeat(node)

  println("✅ test_send_append_entries passed")
}

// ============================================
// 메인 테스트 실행
// ============================================

fn main() {
  println("🌐 Raft RPC Server - Tests")
  println("===========================")

  test_rpc_server_start()
  test_identify_rpc_type()
  test_send_request_vote()
  test_send_append_entries()

  println()
  println("✅ All RPC server tests passed!")
}

// 실행
main()
